// ── Librerías pesadas — lazy load bajo demanda ────────────────────────────
// jsPDF (~500KB) + autotable (~100KB) + XLSX (~800KB) = ~1.4MB que NO se cargan
// al iniciar la app. Solo se descargan la primera vez que el usuario genera un
// PDF o exporta Excel. Vite hace code splitting automático con dynamic imports.
//
// Uso: const {jsPDF, autoTable} = await cargarPDF()
//      const XLSX = await cargarXLSX()
let _jsPDF = null, _autoTable = null, _XLSX = null

const cargarPDF = async () => {
  if (!_jsPDF) {
    const [mod1, mod2] = await Promise.all([
      import('jspdf'),
      import('jspdf-autotable'),
    ])
    _jsPDF    = mod1.default
    _autoTable = mod2.default
  }
  return { jsPDF: _jsPDF, autoTable: _autoTable }
}

const cargarXLSX = async () => {
  if (!_XLSX) {
    const mod = await import('xlsx')
    _XLSX = mod
  }
  return _XLSX
}

// ─── HELPERS ───────────────────────────────────────────────
// Helper global: cargar todos los registros superando límite 1000 de Supabase
const fetchAll = async (queryBuilder) => {
  const pageSize = 1000; let allData = []; let from = 0; let hasMore = true
  while(hasMore) {
    const {data,error} = await queryBuilder.range(from, from+pageSize-1)
    if(error) throw error
    if(!data||data.length===0) break
    allData = [...allData,...data]; hasMore = data.length===pageSize; from += pageSize
    await new Promise(r=>setTimeout(r,0))
  }
  return allData
}

