// ── Anti-fantasma: descontar stock_maipu en CD al crear solicitud ──────────
// Usa RPC atómica (UPDATE stock_maipu = stock_maipu - delta) — sin race condition
// items: [{sku, cantidad_a_despachar}] o [{sku, cantidad}]
const descontarStockCD = async (items, supabase) => {
  const conCant=(items||[]).filter(it=>it.sku&&String(it.sku).trim()&&(it.cantidad_a_despachar||it.cantidad||0)>0)
  if(!conCant.length) return
  // Promise.all sobre RPCs atómicas — cada una es un UPDATE sin READ previo
  await Promise.all(conCant.map(it=>{
    const cant=it.cantidad_a_despachar||it.cantidad||0
    return supabase.rpc('log_rpc_descontar_stock',{p_sku:it.sku,p_delta:cant})
  }))
}

// ══════════════════════════════════════════════════════════════════
// TABLA DE MOVIMIENTOS DE STOCK — REFERENCIA PARA DESARROLLO
// ══════════════════════════════════════════════════════════════════
// TIPO              CREAR              ANULAR/RECHAZAR    RECIBIR
// ──────────────────────────────────────────────────────────────────
// Reposición normal ↓stock_maipu(CD)   ↑stock_maipu(CD)   ↑stock_maipu(CD)*
// Urgente           ↓stock_maipu(CD)   ↑stock_maipu(CD)   ↑stock_maipu(CD)*
// Traspaso interno  ↓stock_actual(BOD) ↑stock_actual(BOD) ↑stock_actual(SALA)
// Flujo inverso     [no descuenta]     [no libera]        ↑stock_maipu(CD)
// Lateral           ↓stock_actual(SUC) ↑stock_actual(SUC) ↑stock_actual(DEST)
// ──────────────────────────────────────────────────────────────────
// *stock_maipu(CD) = columna stock_maipu en tabla productos, sucursal cd_mp
// stock_actual(BOD/SUC/SALA) = columna stock_actual, sucursal específica
// REGLA CLAVE: nunca llamar liberarReservaStock en recepción de traspaso_interno
// ══════════════════════════════════════════════════════════════════
// Opera sobre stock_actual de la bodega auxiliar — no sobre stock_maipu del CD
// Al crear traspaso: descuenta de la_bodega. Al recibir: suma a stock_actual de la sala.
const descontarStockSucursal = async (items, sucursalCodigo) => {
  const conCant=(items||[]).filter(it=>it.sku&&(it.cantidad_a_despachar||it.cantidad||0)>0)
  if(!conCant.length||!sucursalCodigo) return
  await Promise.all(conCant.map(it=>{
    const cant=it.cantidad_a_despachar||it.cantidad||0
    return supabase.rpc('log_rpc_descontar_stock_sucursal',{p_sku:it.sku,p_sucursal_codigo:sucursalCodigo,p_delta:cant})
  }))
}
const sumarStockSucursal = async (items, sucursalCodigo) => {
  const conCant=(items||[]).filter(it=>it.sku&&(it.cantidad_a_despachar||it.cantidad||it.cant_recibida||0)>0)
  if(!conCant.length||!sucursalCodigo) return
  await Promise.all(conCant.map(it=>{
    const cant=it.cant_recibida??it.cantidad_a_despachar??it.cantidad??0
    return supabase.rpc('log_rpc_liberar_stock_sucursal',{p_sku:it.sku,p_sucursal_codigo:sucursalCodigo,p_delta:cant})
  }))
}

// ── Liberar stock_maipu en CD al anular solicitud ───────────────────────────
// Usa RPC atómica (UPDATE stock_maipu = stock_maipu + delta) — sin race condition
const liberarStockCD = async (items, supabase) => {
  const conCant=(items||[]).filter(it=>it.sku&&(it.cantidad_a_despachar||0)>0)
  if(!conCant.length) return
  await Promise.all(conCant.map(it=>
    supabase.rpc('log_rpc_liberar_stock',{p_sku:it.sku,p_delta:it.cantidad_a_despachar||0})
  ))
}

// Regla de oro: validar observaciones — mín 3 palabras o 12 chars, sin repeticiones >3 consecutivas
const validarObs = (t) => {
  if (!t || !t.trim()) return {ok:false, msg:'La observación es obligatoria'}
  const s = t.trim()
  if (s.length < 12 && s.split(/\s+/).filter(w=>w.length>0).length < 3) return {ok:false, msg:'Mínimo 3 palabras o 12 caracteres'}
  // Detectar caracteres repetidos >3 veces consecutivas
  if (/(.)\1{3,}/i.test(s)) return {ok:false, msg:'No se permiten caracteres repetidos más de 3 veces consecutivas'}
  // Detectar patrones como "aaa", "111", "xxx"
  if (/^(.)\1+$/i.test(s.replace(/\s/g,''))) return {ok:false, msg:'La observación no puede ser un solo carácter repetido'}
  return {ok:true, msg:''}
}

// Extraer fecha del Excel Bsale (celda B2 de hoja reposition_stock)
const extraerFechaExcel = (wb, utils) => {
  const hoja = wb.SheetNames.find(n=>n.toLowerCase().includes('reposition')||n.toLowerCase().includes('reposicion'))
  if (!hoja) return null
  const ws = wb.Sheets[hoja]
  const raw = utils.sheet_to_json(ws, {header:1, defval:''})
  // B2 = raw[1][1]
  const fechaRaw = raw[1]?.[1]
  if (!fechaRaw) return null
  // Puede venir como "06/05/2026" o como fecha JS
  if (typeof fechaRaw === 'string') {
    const parts = fechaRaw.split('/')
    if (parts.length === 3) return `${parts[2]}-${parts[1].padStart(2,'0')}-${parts[0].padStart(2,'0')}`
    return fechaRaw
  }
  if (fechaRaw instanceof Date) return fechaRaw.toISOString().slice(0,10)
  return String(fechaRaw)
}

