// ╔══════════════════════════════════════════════════════════════════════════════╗
// ║  REGLAS DE NEGOCIO — leer ANTES de modificar permisos, flujos o stock      ║
// ╚══════════════════════════════════════════════════════════════════════════════╝
//
// PERMISOS
// R1  jefe_bodega + sucursal_codigo != cd_mp → opera IGUAL que jefe_sucursal.
//     No ve CD, no puede validar/despachar desde el almacén central.
// R2  coordinador + sucursal_codigo != cd_mp → opera IGUAL que coordinador_suc.
// R3  jefe_sucursal / coordinador_suc SIEMPRE requieren sucursal_codigo asignada.
//     Sin sucursal → el usuario no verá ninguna solicitud.
// R4  jefe_sucursal con sucursal_codigo='cd_mp' es config incorrecta — bloqueado al guardar.
// R5  Cualquier cambio a isSucursalOnly / esCDUser / canCD impacta en cascada:
//     loadSols · checkPendientes · canRecibir · Sidebar · DashboardGerencial ·
//     ForecastView · RendimientoTrabajadores · RepoAnalisis · TraspasoInternoModal
//
// SUCURSALES
// R6  la ↔ la_bodega son la misma operación física — regla BIDIRECCIONAL.
//     Un trabajador de la_bodega pertenece también a la, y viceversa.
//     Aplica en: perteneceASuc · perteneceASucFiltro · idsPermitidos (Rendimiento)
// R7  bodega_auxiliar (la_bodega) no tiene demanda propia — sus ventas están bajo 'la'.
//     El Forecast y las métricas de demanda deben usar la sucursal padre, no la_bodega.
//
// STOCK
// R8  Anti-fantasma: al crear solicitud → descontar stock_maipu (CD) con rpc_descontar_stock.
//     Al anular → liberar con rpc_liberar_stock. Sin esto el stock del CD queda inflado.
// R9  Traspaso interno: el stock se mueve en la BODEGA AUXILIAR (stock_actual de la_bodega),
//     NO en stock_maipu del CD. Usar rpc_descontar_stock_sucursal / rpc_liberar_stock_sucursal.
// R10 Al recibir un traspaso interno → sumar stock_actual en la sala destino.
//
// FLUJOS
// R11 T0 (Approval Time) solo mide solicitudes tipo 'extraordinaria'.
//     Las reposiciones normales las crea el CD → T0≈0 → distorsionan el promedio.
// R12 traspaso_interno y venta_directa se excluyen de los KPIs de Lead Time CD
//     (T1, T3, Lead Time total) — tienen SLA y flujos distintos.
// R13 Lateral Fase 1: la sucursal ORIGEN acepta/rechaza y prepara con SUS trabajadores.
//     Nace en etapa='solicitado'. Solo pasa a 'analisis' cuando el jefe origen acepta.
// R14 Módulos WMS visibles dependen del rol EFECTIVO (rol + sucursal), no solo del rol.
//     Usar rolEfectivo en Sidebar, no cu.rol directamente.
// R15 NUNCA truncar nombres de productos, motivos, observaciones ni texto ingresado por usuario.
//     PROHIBIDO: overflow:'hidden'+textOverflow:'ellipsis'+whiteSpace:'nowrap' en campos de datos.
//     CORRECTO:  wordBreak:'break-word' para que el texto ajuste al espacio disponible.
//     Excepción permitida: labels fijos del sidebar, badges de estado (texto corto predefinido).
// R16 coordinador_suc tiene MISMA autoridad que jefe_sucursal en operaciones de su sucursal:
//     puede iniciar picking, asignar trabajadores, confirmar recepción y corregir ítems.
//     TODAS sus acciones se registran en sol_etapa_trabajadores con asignado_por_nombre/rol
//     y en solicitudes_reposicion con recibido_por_rol / iniciado_por_rol para métricas.
//
// Principio: el mismo rol puede operar en distintos contextos.
// 'jefe_bodega' en CD Maipú → opera el almacén central (todo el flujo).
// 'jefe_bodega' en La Granja → opera SOLO su sucursal, exactamente igual que 'jefe_sucursal'.
// 'coordinador' en CD → gestiona despachos del CD.
// 'coordinador' en sucursal → apoya al jefe de esa sucursal.
//
// Regla: si el rol "implica CD" (jefe_bodega / coordinador) pero el usuario
// tiene sucursal_codigo distinto de cd_mp → su CONTEXTO es de sucursal.

// ¿El usuario opera desde el CD Maipú (acceso al flujo central)?
const esCDUser = u => {
  if (!u) return false
  if (u.rol==='admin') return true
  if (u.rol==='jefe_bodega'||u.rol==='coordinador')
    return !u.sucursal_codigo || u.sucursal_codigo==='cd_mp'
  return false
}

// ¿El usuario está acotado a una sucursal específica?
// Incluye jefe_sucursal, coordinador_suc, Y cualquier jefe_bodega/coordinador
// asignado a una sucursal distinta del CD.
const isSucursalOnly = u => {
  if (!u) return false
  if (u.rol==='jefe_sucursal'||u.rol==='coordinador_suc') return true
  if ((u.rol==='jefe_bodega'||u.rol==='coordinador') &&
      u.sucursal_codigo && u.sucursal_codigo!=='cd_mp') return true
  return false
}

// ¿El usuario pertenece a una sucursal (no CD)?
const esSucursalUser = u => !!u?.sucursal_codigo && u.sucursal_codigo!=='cd_mp'

// Sucursal chica: tipo_sucursal='chica' en BD (ej: Los Angeles)
// En sucursal chica el coordinador_suc opera con permisos ampliados
const isSucursalChica = (sucCodigo, sucs=[]) => {
  const s = sucs.find(x=>x.codigo===sucCodigo)
  if(!s) return false
  // Soportar campo tipo_sucursal='chica' si existe en BD
  if(s.tipo_sucursal==='chica') return true
  // Fallback: sucursal pequeña = no es CD y no es bodega auxiliar
  // (mp, la, lg son sucursales pequeñas sin jefe de bodega dedicado)
  return s.tipo_ubicacion==='sucursal'&&!s.es_centro_distribucion
}

// Puede operar con permisos de jefe (admin, jefe_bodega, jefe_sucursal,
// o coordinador_suc en sucursal chica)
const canOperarComoJefe = (cu, sucs=[]) => {
  if(!cu) return false
  if(cu.rol==='admin'||cu.rol==='jefe_bodega'||cu.rol==='jefe_sucursal') return true
  if(cu.rol==='coordinador_suc' && isSucursalChica(cu.sucursal_codigo, sucs)) return true
  return false
}

// canCD — puede operar el flujo del CD (validar stock, preparar despachos)
const canCD = (u, sol=null) => {
  if (!u) return false
  if (u.rol==='admin') return true
  // Traspaso interno: jefe/coordinador de la sucursal operan su bodega auxiliar
  if (sol?.tipo_sol==='traspaso_interno') {
    if (esCDUser(u)) return true
    if (isSucursalOnly(u) && u.sucursal_codigo===sol.sucursal_codigo) return true
    return false
  }
  // Lateral Fase 1: el jefe de la sucursal ORIGEN prepara y despacha al CD
  if (sol?.tipo_sol==='lateral' && sol?.fase_lateral===1) {
    if (esCDUser(u)) return true
    if (isSucursalOnly(u) && u.sucursal_codigo===sol.sucursal_codigo) return true
    return false
  }
  // Operación CD normal: solo usuarios efectivamente en el CD
  if (isSucursalOnly(u)) return false
  return esCDUser(u) && (hp(u,'validar_cd')||hp(u,'despacho_cd'))
}

// canRecibir — quién puede confirmar recepción en destino
const canRecibir = (u, codDestino, esFlujoInverso=false) => {
  if (!u) return false
  if (hp(u,'todo')) return true
  if (!hp(u,'recepcion')) return false
  if (esFlujoInverso) {
    // Flujo inverso recibe el CD — solo usuarios del CD
    return esCDUser(u)
  }
  // Coordinador CD sin sucursal propia no confirma en sucursal
  if (u.rol==='coordinador' && esCDUser(u)) return false
  // Usuarios de sucursal (incluyendo jefe_bodega en sucursal) reciben solo en la suya
  if (isSucursalOnly(u)) return u.sucursal_codigo===codDestino
  // jefe_bodega CD y admin confirman en cualquier sucursal
  return true
}

// ¿Puede ver el dashboard operativo?
const canVerDash = u => hp(u,'ver_dash')
// ¿Puede ver KPIs gerenciales?
const canVerKpis = u => hp(u,'todo')||hp(u,'ver_kpis')

