// LoadingOverlay — overlay de carga grande y visible para operaciones pesadas
function LoadingOverlay({show=false, msg='Procesando...'}) {
  if(!show) return null
  return(
    <div style={{
      position:'fixed',inset:0,zIndex:9999,
      background:'rgba(26,26,46,0.75)',
      backdropFilter:'blur(4px)',
      display:'flex',flexDirection:'column',
      alignItems:'center',justifyContent:'center',
      gap:20,
    }}>
      {/* Spinner animado */}
      <div style={{position:'relative',width:72,height:72}}>
        <div style={{
          position:'absolute',inset:0,borderRadius:36,
          border:'5px solid rgba(255,255,255,0.15)',
        }}/>
        <div style={{
          position:'absolute',inset:0,borderRadius:36,
          border:'5px solid transparent',
          borderTopColor:'#007AFF',
          animation:'spinLoad 0.8s linear infinite',
        }}/>
        <div style={{
          position:'absolute',inset:8,borderRadius:28,
          background:'#007AFF15',
          display:'flex',alignItems:'center',justifyContent:'center',
          fontSize:24,
        }}>📦</div>
      </div>
      <div style={{textAlign:'center'}}>
        <div style={{fontSize:18,fontWeight:700,color:'#fff',marginBottom:4}}>{msg}</div>
        <div style={{fontSize:13,color:'rgba(255,255,255,0.55)'}}>Por favor espera...</div>
      </div>
      <style>{`@keyframes spinLoad{to{transform:rotate(360deg)}}`}</style>
    </div>
  )
}

