// ── UniversalHelpMenu ─────────────────────────────────────────────────────────
function UniversalHelpMenu({context='repo', show, onClose}) {
  const sop = SOP_DICT[context] || SOP_DICT.repo
  return(
    <Sheet show={show} onClose={onClose} title={`📖 ${sop.titulo}`}>
      <div style={{display:'flex',flexDirection:'column',gap:12}}>
        {sop.pasos.map((p,i)=>(
          <div key={i} style={{display:'flex',gap:12,alignItems:'flex-start'}}>
            <div style={{width:28,height:28,borderRadius:14,background:'#007AFF',
              color:'#fff',display:'flex',alignItems:'center',justifyContent:'center',
              fontSize:12,fontWeight:800,flexShrink:0}}>{p.n}</div>
            <div>
              <div style={{fontSize:13,fontWeight:700,color:'#1C1C1E'}}>{p.l}</div>
              <div style={{fontSize:12,color:'#6D6D72',marginTop:3,lineHeight:1.5}}>{p.d}</div>
            </div>
          </div>
        ))}
        {sop.tip&&(
          <div style={{padding:'10px 14px',background:'#FF950010',borderRadius:8,
            border:'1px solid #FF950030',marginTop:4}}>
            <div style={{fontSize:11,fontWeight:700,color:'#FF9500',marginBottom:3}}>
              💡 Tip operativo
            </div>
            <div style={{fontSize:12,color:'#3C3C3E',lineHeight:1.5}}>{sop.tip}</div>
          </div>
        )}
        {sop.manual_url&&(
          <a href={sop.manual_url} target="_blank" rel="noopener noreferrer"
            style={{display:'flex',alignItems:'center',gap:8,padding:'10px 14px',
              background:'#007AFF10',borderRadius:8,border:'1px solid #007AFF30',
              marginTop:4,textDecoration:'none',cursor:'pointer'}}>
            <div style={{fontSize:18}}>📄</div>
            <div>
              <div style={{fontSize:12,fontWeight:700,color:'#007AFF'}}>
                Descargar Manual del Proceso
              </div>
              <div style={{fontSize:11,color:'#8E8E93'}}>
                Proceso Toma de Inventario — Departamento de Operaciones
              </div>
            </div>
          </a>
        )}
      </div>
    </Sheet>
  )
}

