// HELPER: verificarBloqueoInventario
// Verifica si hay inventario activo que bloquea un movimiento
// tipo_inventario GENERAL → bloquea todo
// tipo_inventario CICLICO → bloquea solo si el SKU o categoría está en conteo
// ════════════════════════════════════════════════════════════
const verificarBloqueoInventario = async (sucursal_codigo, skus=[], categorias=[]) => {
  try {
    // Buscar inventarios EN_CONTEO o PRE_INVENTARIO en esa sucursal
    const {data:invs} = await supabase
      .from('log_inv_cabeceras')
      .select('id,tipo_inventario,categorias_asignadas,categoria_asignada')
      .eq('sucursal_codigo', sucursal_codigo)
      .in('estado',['EN_CONTEO','PRE_INVENTARIO'])
      .limit(3)
    if (!invs || invs.length === 0) return {bloqueado:false}

    for (const inv of invs) {
      // GENERAL → bloquea todo movimiento en la sucursal
      if (inv.tipo_inventario === 'GENERAL') {
        return {
          bloqueado: true,
          invId: inv.id,
          tipo: 'GENERAL',
          motivo: `🔒 Inventario general activo en esta sucursal (${inv.id}).

Durante un inventario general NO se pueden generar movimientos de stock.

Coordina con el supervisor del inventario antes de continuar.`,
        }
      }
      // CICLICO → bloquea solo si el SKU pertenece a una categoría inventariada
      if (inv.tipo_inventario === 'CICLICO') {
        const catsBloqueadas = inv.categorias_asignadas || (inv.categoria_asignada ? [inv.categoria_asignada] : [])
        if (catsBloqueadas.length === 0) continue
        // Si se pasaron categorías a verificar
        const catBloqueada = categorias.find(c => catsBloqueadas.includes(c))
        if (catBloqueada) {
          return {
            bloqueado: true,
            invId: inv.id,
            tipo: 'CICLICO',
            motivo: `🔒 Inventario cíclico activo (${inv.id}) incluye la categoría "${catBloqueada}".

No se pueden mover productos de esa categoría mientras se inventarian.

Si el movimiento es urgente, coordina con el supervisor del inventario.`,
            categoriaAfectada: catBloqueada,
          }
        }
      }
    }
    return {bloqueado:false}
  } catch { return {bloqueado:false} }
}

