// Subir adjunto a Supabase Storage
const subirAdjuntoRec = async (file, recId, slot) => {
  if (!file) return null
  try {
    const ext  = file.name.split('.').pop().toLowerCase()
    const path = `recepciones/${recId}/${slot}_${Date.now()}.${ext}`
    const { data, error } = await supabase.storage
      .from('log-recepciones-docs').upload(path, file, {upsert:true})
    if (error) throw error
    const { data: urlData } = supabase.storage.from('log-recepciones-docs').getPublicUrl(path)
    return { url: urlData.publicUrl, path, nombre: file.name, tipo: file.type }
  } catch(e) {
    return null
  }
}

